import { Component, inject, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { ProductService } from '../../services/product.service';
import { Product } from '../../models/product.model';

@Component({
  selector: 'app-product-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './product-list.html',
  styleUrl: './product-list.css',
})
export class ProductListComponent implements OnInit {
  private productService = inject(ProductService);
  private router = inject(Router);
  products: Product[] = [];

  ngOnInit(): void {
    this.productService.getProducts().subscribe(products => {
      this.products = products;
    });
  }

  navigateToAdd(): void {
    this.router.navigate(['/add']);
  }

  navigateToEdit(id: number): void {
    this.router.navigate(['/edit', id]);
  }

  deleteProduct(id: number): void {
    if (confirm('Are you sure you want to delete this product?')) {
      this.productService.deleteProduct(id);
    }
  }
}
<div class="min-h-screen bg-gradient-to-br from-pink-50 to-purple-50 py-8 px-4">
  <div class="max-w-6xl mx-auto">
    <!-- Header -->
    <div class="flex justify-between items-center mb-8">
      <h1 class="text-4xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-pink-600 to-purple-600">Products Management</h1>
      <button 
        (click)="navigateToAdd()"
        class="bg-gradient-to-r from-pink-500 to-rose-500 hover:from-pink-600 hover:to-rose-600 text-white font-bold py-2 px-6 rounded-lg transition duration-200 shadow-lg hover:shadow-xl"
      >
        + Add Product
      </button>
    </div>

    <!-- Products Table -->
    <div *ngIf="products.length > 0" class="bg-white rounded-lg shadow-lg overflow-hidden">
      <div class="overflow-x-auto">
        <table class="w-full">
          <thead class="bg-gray-800 text-white">
            <tr>
              <th class="px-6 py-3 text-left">ID</th>
              <th class="px-6 py-3 text-left">Name</th>
              <th class="px-6 py-3 text-left">Price</th>
              <th class="px-6 py-3 text-left">Description</th>
              <th class="px-6 py-3 text-left">Quantity</th>
              <th class="px-6 py-3 text-center">Actions</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let product of products; let i = index" 
                [class]="i % 2 === 0 ? 'bg-gray-50' : 'bg-white'" 
                class="border-b hover:bg-gray-100 transition duration-150">
              <td class="px-6 py-4 text-gray-700">{{ product.id }}</td>
              <td class="px-6 py-4 font-semibold text-gray-800">{{ product.name }}</td>
              <td class="px-6 py-4 text-gray-700">${{ product.price.toFixed(2) }}</td>
              <td class="px-6 py-4 text-gray-600">{{ product.description }}</td>
              <td class="px-6 py-4">
                <span class="bg-blue-100 text-blue-800 px-3 py-1 rounded-full text-sm font-medium">
                  {{ product.quantity }}
                </span>
              </td>
              <td class="px-6 py-4 text-center space-x-2">
                <button 
                  (click)="navigateToEdit(product.id)"
                  class="bg-blue-500 hover:bg-blue-600 text-white font-semibold py-2 px-4 rounded transition duration-200 ease-in-out inline-block"
                >
                  Edit
                </button>
                <button 
                  (click)="deleteProduct(product.id)"
                  class="bg-red-500 hover:bg-red-600 text-white font-semibold py-2 px-4 rounded transition duration-200 ease-in-out inline-block"
                >
                  Delete
                </button>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- Empty State -->
    <div *ngIf="products.length === 0" class="bg-white rounded-lg shadow-lg p-8 text-center">
      <p class="text-gray-600 text-lg mb-4">No products available.</p>
      <button 
        (click)="navigateToAdd()"
        class="bg-green-500 hover:bg-green-600 text-white font-bold py-2 px-6 rounded-lg transition duration-200 ease-in-out"
      >
        Create Your First Product
      </button>
    </div>
  </div>
</div>
